usageExamples.code:
unsigned int flags = 0b0000;

// شغّل البت الثالث
flags xor_eq 0b0100;  // flags = 0b0100

// أطفئ البت الثالث بنفس القناع
flags xor_eq 0b0100;  // flags = 0b0000

// خاصية XOR: تكرار نفس العملية يعيد الحالة الأصلية

unsigned int options = 0;
const unsigned int VSYNC   = 1 << 0;
const unsigned int DEPTH   = 1 << 1;
const unsigned int CULLING = 1 << 2;

// فعّل VSync والعمق عند البدء
options or_eq VSYNC | DEPTH;   // options = 0b0011

// فعّل Culling لاحقًا
options xor_eq CULLING;        // options = 0b0111

// أطفئ VSync (كان مفعّلًا، فانقلب إلى معطّل)
options xor_eq VSYNC;          // options = 0b0110

// الآن: DEPTH و CULLING مفعّلان، VSYNC معطّل

unsigned int val = 0b1100;
unsigned int mask = 0b1010;

// or_eq: يُشغّل البتات بغض النظر عن حالتها الحالية
val = 0b1100;
val or_eq mask;   // val = 0b1110

// and_eq: يُبقي البتات المشتركة فقط (يحذف ما ليس في القناع)
val = 0b1100;
val and_eq mask;  // val = 0b1000

// xor_eq: يقلب البتات — 1 تصبح 0 و 0 تصبح 1
val = 0b1100;
val xor_eq mask;  // val = 0b0110

